export default async function ({ execution_id }) {
  const r = await fetch('/platform/automation/v1/executions/' + execution_id + '/tasks/get-status/result');
  const b = await r.json();
  const status = (b?.AutomationExecution?.AutomationExecutionStatus || '').toUpperCase();
  if (status === 'INPROGRESS' || status === 'PENDING') {
    throw new Error('Automation still running: ' + status);
  }
  return b;
}
